import { loadConfig, type DmScope, type OpenClawConfig } from './src/config/config.js';
import { resolveAgentRoute } from './src/plugin-sdk/routing.js';

type LinkedIdentity = {
  channel: 'telegram' | 'whatsapp' | 'webchat';
  peerId: string;
  accountId?: string;
};

const linkedHuman: readonly LinkedIdentity[] = [
  { channel: 'telegram', accountId: 'bot-a', peerId: '12345' },
  { channel: 'whatsapp', accountId: 'wa-a', peerId: '+15551234567' },
  { channel: 'webchat', peerId: 'browser-user' },
];

const modes: readonly DmScope[] = [
  'main',
  'per-peer',
  'per-channel-peer',
  'per-account-channel-peer',
];

const base = loadConfig();

function withMode(mode: DmScope): OpenClawConfig {
  return {
    ...base,
    session: {
      ...(base.session ?? {}),
      dmScope: mode,
      identityLinks: {
        ...(base.session?.identityLinks ?? {}),
        audit_user: linkedHuman.map(({ channel, peerId }) => `${channel}:${peerId}`),
      },
    },
  };
}

function resolveSessionKey(cfg: OpenClawConfig, entry: LinkedIdentity): string {
  return resolveAgentRoute({
    cfg,
    channel: entry.channel,
    accountId: entry.accountId,
    peer: { kind: 'direct', id: entry.peerId },
  }).sessionKey;
}

const rows = modes.map((mode) => {
  const cfg = withMode(mode);
  const telegram = resolveSessionKey(cfg, linkedHuman[0]);
  const whatsapp = resolveSessionKey(cfg, linkedHuman[1]);
  const webchat = resolveSessionKey(cfg, linkedHuman[2]);
  const telegramOtherAccount = resolveAgentRoute({
    cfg,
    channel: 'telegram',
    accountId: 'bot-b',
    peer: { kind: 'direct', id: linkedHuman[0].peerId },
  }).sessionKey;

  return {
    mode,
    telegram,
    whatsapp,
    webchat,
    telegramOtherAccount,
    sameAcrossChannels: new Set([telegram, whatsapp, webchat]).size === 1,
    sameAcrossTelegramAccounts: telegram === telegramOtherAccount,
  };
});

console.table(rows);
