import { definePluginEntry } from 'openclaw/plugin-sdk/plugin-entry';

type RouteDecision = {
  provider: string;
  model: string;
  note: string;
};

function pickRoute(prompt: string): RouteDecision | undefined {
  const text = prompt.toLowerCase();

  if (['code', 'debug', 'refactor', 'fix', 'typescript', 'javascript', 'python'].some((token) => text.includes(token))) {
    return {
      provider: 'anthropic',
      model: 'sonnet-4.6',
      note: 'coding-style prompt -> anthropic/sonnet-4.6',
    };
  }

  if (
    text.length < 240 &&
    ['weather', 'time', 'translate', 'summarize', 'who is', 'what is'].some((token) => text.includes(token))
  ) {
    return {
      provider: 'openai',
      model: 'gpt-5.4-mini',
      note: 'light factual prompt -> openai/gpt-5.4-mini',
    };
  }

  return undefined;
}

export default definePluginEntry({
  id: 'smart-model-router',
  name: 'Smart Model Router',
  description: 'Per-message model selection without sticky session overrides.',
  register(api) {
    api.on('before_model_resolve', async (event) => {
      const route = pickRoute(event.prompt);
      return route
        ? {
            providerOverride: route.provider,
            modelOverride: route.model,
          }
        : undefined;
    });

    api.on('before_prompt_build', async (event) => {
      const route = pickRoute(event.prompt);
      return route
        ? {
            prependContext: `Routing note: ${route.note}`,
          }
        : undefined;
    });
  },
});
