import { randomUUID } from 'node:crypto';
import { loadConfig } from './src/config/config.js';
import { resolveGatewayClientBootstrap } from './src/gateway/client-bootstrap.js';
import { GatewayClient } from './src/gateway/client.js';
import type { SessionsListResult, SessionsPreviewResult } from './src/gateway/session-utils.types.js';

async function connectGateway(): Promise<GatewayClient> {
  const config = loadConfig();
  const bootstrap = await resolveGatewayClientBootstrap({ config });

  return await new Promise<GatewayClient>((resolve, reject) => {
    let settled = false;
    const finish = (error?: unknown, client?: GatewayClient) => {
      if (settled) {
        return;
      }
      settled = true;
      clearTimeout(timer);
      if (error) {
        reject(error instanceof Error ? error : new Error(String(error)));
      } else {
        resolve(client as GatewayClient);
      }
    };

    const client = new GatewayClient({
      url: bootstrap.url,
      token: bootstrap.auth.token,
      password: bootstrap.auth.password,
      onHelloOk: () => finish(undefined, client),
      onConnectError: (error) => finish(error),
      onClose: (code, reason) => finish(new Error(`gateway closed (${code}): ${reason}`)),
    });

    const timer = setTimeout(() => finish(new Error('gateway connect timeout')), 10_000);
    timer.unref?.();
    client.start();
  });
}

export async function driveExternalChatSession(params: {
  agentId: string;
  externalChatId: string;
  message: string;
}) {
  const client = await connectGateway();

  try {
    const created = await client.request<{ ok: true; key: string }>('sessions.create', {
      key: `external-chat:${params.externalChatId}`,
      agentId: params.agentId,
    });
    const key = created.key;

    await client.request('sessions.patch', {
      key,
      model: 'openai/gpt-5.4',
      reasoningLevel: 'on',
    });

    await client.request('sessions.send', {
      key,
      message: params.message,
      idempotencyKey: randomUUID(),
    });

    const [list, preview] = await Promise.all([
      client.request<SessionsListResult>('sessions.list', {
        search: key,
        limit: 50,
        includeGlobal: true,
        includeUnknown: true,
      }),
      client.request<SessionsPreviewResult>('sessions.preview', {
        keys: [key],
        limit: 6,
        maxChars: 160,
      }),
    ]);

    await client.request('sessions.compact', { key });
    await client.request('sessions.reset', { key, reason: 'new' });

    return {
      key,
      session: list.sessions.find((entry) => entry.key === key),
      preview: preview.previews.find((entry) => entry.key === key)?.items ?? [],
    };
  } finally {
    await client.stopAndWait().catch(() => client.stop());
  }
}

const agentId = process.argv[2] ?? 'main';
const externalChatId = process.argv[3] ?? 'demo-chat';
const message = process.argv[4] ?? 'Give me a one-line session-health summary.';

console.dir(await driveExternalChatSession({ agentId, externalChatId, message }), { depth: null });
