import type { AgentMessage } from '@mariozechner/pi-agent-core';
import {
  buildMemorySystemPromptAddition,
  delegateCompactionToRuntime,
  type ContextEngine,
} from 'openclaw/plugin-sdk';
import { definePluginEntry } from 'openclaw/plugin-sdk/plugin-entry';

const MAX_BUFFER = 24;
const MAX_WORKING_SET = 8;

export default definePluginEntry({
  id: 'viewport-context',
  name: 'Viewport Context',
  description: 'Keep a short working set in front of the model.',
  register(api) {
    api.registerContextEngine('viewport-context', () => {
      const bySession = new Map<string, AgentMessage[]>();

      return {
        info: {
          id: 'viewport-context',
          name: 'Viewport Context',
          ownsCompaction: false,
        },
        async ingest({ sessionId, message }) {
          const next = [...(bySession.get(sessionId) ?? []), message].slice(-MAX_BUFFER);
          bySession.set(sessionId, next);
          return { ingested: true };
        },
        async assemble({ sessionId, messages, availableTools, citationsMode }) {
          const workingSet = (bySession.get(sessionId) ?? messages).slice(-MAX_WORKING_SET);
          const estimatedTokens = Math.ceil(
            workingSet.reduce((sum, message) => sum + JSON.stringify(message).length / 4, 0),
          );

          return {
            messages: workingSet,
            estimatedTokens,
            systemPromptAddition: buildMemorySystemPromptAddition({
              availableTools: availableTools ?? new Set<string>(),
              citationsMode,
            }),
          };
        },
        compact: delegateCompactionToRuntime,
        async dispose() {
          bySession.clear();
        },
      } satisfies ContextEngine;
    });
  },
});
