          sourceSessionKey?: string;
          targetSessionKey?: string;
          controllerId?: string;
        };

        if (!input.sourceSessionKey?.trim() || !input.targetSessionKey?.trim()) {
          respond(true, { ok: false, error: 'sourceSessionKey and targetSessionKey are required.' });
          return;
        }

        const source = api.runtime.tasks.flows
          .bindSession({ sessionKey: input.sourceSessionKey })
          .findLatest();
        if (!source) {
          respond(true, { ok: false, error: 'No source plan found.' });
          return;
        }

        const target = api.runtime.taskFlow.bindSession({ sessionKey: input.targetSessionKey });
        const existing = target.findLatest();
        const reusableTarget =
          existing &&
          existing.syncMode === 'managed' &&
          existing.goal === source.goal &&
          isOpenStatus(existing.status)
            ? existing
            : undefined;

        const mirroredState = {
          mirroredFrom: input.sourceSessionKey,
          sourceFlowId: source.id,
          sourceStatus: source.status,
          sourceCurrentStep: source.currentStep ?? null,
          sourceState: source.state ?? null,
        };

        const createMirror = () =>
          target.createManaged({
            controllerId: input.controllerId ?? 'shared-plan-mirror',
            goal: source.goal,
            notifyPolicy: source.notifyPolicy,
            status:
              source.status === 'waiting' || source.status === 'blocked' ? 'running' : source.status,
            currentStep: source.currentStep ?? null,
            stateJson: mirroredState,
            waitJson:
              source.status === 'waiting' || source.status === 'blocked'
                ? source.wait ?? null
                : null,
            endedAt: source.endedAt ?? null,
          });

        if (!reusableTarget) {
          const created = createMirror();
          if (source.status === 'waiting' || source.status === 'blocked') {
            const seeded = target.setWaiting({
              flowId: created.flowId,
              expectedRevision: created.revision,
              currentStep: source.currentStep ?? null,
              stateJson: mirroredState,
              waitJson: source.wait ?? null,
              blockedTaskId: source.blocked?.taskId ?? null,
              blockedSummary: source.blocked?.summary ?? null,
            });
            if (!seeded.applied) {
              respond(true, { ok: false, code: seeded.code, error: 'Mirror creation was rejected.' });
              return;
            }
          }

          respond(true, {
            ok: true,
            sourceFlowId: source.id,
            mirroredFlowId: created.flowId,
            sourceStatus: source.status,
            taskSummary: source.taskSummary,
          });
          return;
        }

        const mutation =
          source.status === 'waiting' || source.status === 'blocked'
            ? target.setWaiting({
                flowId: reusableTarget.flowId,
                expectedRevision: reusableTarget.revision,
                currentStep: source.currentStep ?? null,
                stateJson: mirroredState,
                waitJson: source.wait ?? null,
                blockedTaskId: source.blocked?.taskId ?? null,
                blockedSummary: source.blocked?.summary ?? null,
              })
            : source.status === 'queued' || source.status === 'running'
              ? target.resume({
                  flowId: reusableTarget.flowId,
                  expectedRevision: reusableTarget.revision,
                  status: source.status,
                  currentStep: source.currentStep ?? null,
                  stateJson: mirroredState,
                })
              : source.status === 'succeeded'
                ? target.finish({
                    flowId: reusableTarget.flowId,
                    expectedRevision: reusableTarget.revision,
                    stateJson: mirroredState,
                    endedAt: source.endedAt ?? Date.now(),
                  })
                : target.fail({
                    flowId: reusableTarget.flowId,
                    expectedRevision: reusableTarget.revision,
                    stateJson: mirroredState,
                    blockedTaskId: source.blocked?.taskId ?? null,
                    blockedSummary: source.blocked?.summary ?? `Source plan is ${source.status}.`,
                    endedAt: source.endedAt ?? Date.now(),
                  });

        if (!mutation.applied) {
          respond(true, { ok: false, code: mutation.code, error: 'Mirror update was rejected.' });
          return;
        }

        respond(true, {
          ok: true,
          sourceFlowId: source.id,
          mirroredFlowId: mutation.flow.flowId,
          sourceStatus: source.status,
          taskSummary: source.taskSummary,
        });
      },
      { scope: 'operator.write' },
    );
  },
});
