import type { SessionEntry } from "../config/sessions.js";
import { resolveActiveFallbackState } from "../status/fallback-notice-state.js";
import { resolveSelectedAndActiveModel } from "./model-runtime.js";

type ModelSectionParams = {
  selectedProvider: string;
  selectedModel: string;
  configuredFallbacks?: string[];
  sessionEntry?: Pick<
    SessionEntry,
    | "modelProvider"
    | "model"
    | "fallbackNoticeSelectedModel"
    | "fallbackNoticeActiveModel"
    | "fallbackNoticeReason"
  >;
  selectedAuthLabel?: string;
  activeAuthLabel?: string;
};

export function buildModelSectionLines(params: ModelSectionParams): string[] {
  const modelRefs = resolveSelectedAndActiveModel({
    selectedProvider: params.selectedProvider,
    selectedModel: params.selectedModel,
    sessionEntry: params.sessionEntry,
  });
  const fallbackState = resolveActiveFallbackState({
    selectedModelRef: modelRefs.selected.label,
    activeModelRef: modelRefs.active.label,
    state: params.sessionEntry,
  });
  const configuredFallbacksLine = params.configuredFallbacks?.length
    ? `🔄 Fallbacks: ${params.configuredFallbacks.join(", ")}`
    : null;
  const showFallbackAuth =
    params.activeAuthLabel && params.activeAuthLabel !== params.selectedAuthLabel;
  const fallbackLine = fallbackState.active
    ? `↪️ Fallback: ${modelRefs.active.label}${
        showFallbackAuth ? ` · 🔑 ${params.activeAuthLabel}` : ""
      } (${fallbackState.reason ?? "selected model unavailable"})`
    : null;

  return [
    `🧠 Model: ${modelRefs.selected.label}${
      params.selectedAuthLabel ? ` · 🔑 ${params.selectedAuthLabel}` : ""
    }`,
    configuredFallbacksLine,
    fallbackLine,
  ].filter((line): line is string => Boolean(line));
}
