Register both surfaces from the same plugin entry: the web-fetch provider gives OpenClaw a generic capability, while the named tool exposes TinyFish-specific options.

```ts
import { Type } from "@sinclair/typebox";
import { definePluginEntry, type AnyAgentTool, type OpenClawPluginApi } from "openclaw/plugin-sdk/plugin-entry";
import { jsonResult, readStringParam, type WebFetchProviderPlugin } from "openclaw/plugin-sdk/provider-web-fetch";

type TinyFishConfig = { apiKey?: string; endpoint?: string };
const credentialPath = "plugins.entries.tinyfish.config.webFetch.apiKey";

function apiKeyFrom(config?: TinyFishConfig) {
  return config?.apiKey || process.env.TINYFISH_API_KEY;
}

async function runTinyFish(config: TinyFishConfig | undefined, args: Record<string, unknown>) {
  const apiKey = apiKeyFrom(config);
  if (!apiKey) throw new Error("TinyFish API key is not configured.");
  const response = await fetch(config?.endpoint || "https://agent.tinyfish.ai/v1/automation/run", {
    method: "POST",
    headers: { "content-type": "application/json", "x-api-key": apiKey },
    body: JSON.stringify({
      url: String(args.url || ""),
      goal: String(args.goal || ""),
      browser_profile: args.stealth === true ? "stealth" : "default",
      proxy_config: typeof args.proxyCountry === "string" ? { enabled: true, country_code: args.proxyCountry } : undefined,
    }),
  });
  const text = await response.text();
  if (!response.ok) throw new Error(`TinyFish returned ${response.status}: ${text}`);
  return JSON.parse(text) as Record<string, unknown>;
}

function createTinyFishProvider(): WebFetchProviderPlugin {
  return {
    id: "tinyfish",
    label: "TinyFish Web Agent",
    hint: "Hosted browser automation for interactive pages.",
    credentialLabel: "TinyFish API key",
    envVars: ["TINYFISH_API_KEY"],
    placeholder: "tf_...",
    signupUrl: "https://agent.tinyfish.ai/",
    credentialPath,
    getCredentialValue: (fetchConfig) => (fetchConfig as TinyFishConfig | undefined)?.apiKey,
    setCredentialValue: (target, value) => { target.apiKey = value; },
    getConfiguredCredentialValue: (config) =>
      (config?.plugins?.entries?.tinyfish?.config as { webFetch?: TinyFishConfig } | undefined)?.webFetch?.apiKey,
    setConfiguredCredentialValue: (configTarget, value) => {
      const entries = ((configTarget.plugins ??= {}).entries ??= {});
      const entry = (entries.tinyfish ??= { config: {} });
      ((entry.config as { webFetch?: Record<string, unknown> }).webFetch ??= {}).apiKey = value;
    },
    createTool: ({ fetchConfig }) => ({
      description: "Run a browser automation goal and return structured data.",
      parameters: { type: "object", required: ["url", "goal"], properties: { url: { type: "string" }, goal: { type: "string" } } },
      execute: (args) => runTinyFish(fetchConfig as TinyFishConfig | undefined, args),
    }),
  };
}

function createTinyFishTool(api: OpenClawPluginApi): AnyAgentTool {
  return {
    name: "tinyfish_web_agent",
    label: "TinyFish Web Agent",
    description: "Run a TinyFish browser automation task.",
