gold_answer:
The plugin keeps the native boundary outside core: mobile nodes post signed snapshots, and agents only read normalized summaries through a tool.

```ts
import { createHmac, timingSafeEqual } from "node:crypto";
import type { IncomingMessage } from "node:http";
import { Type } from "@sinclair/typebox";
import { definePluginEntry, type AnyAgentTool, type OpenClawPluginApi } from "openclaw/plugin-sdk/plugin-entry";
import { jsonResult, readStringParam } from "openclaw/plugin-sdk/channel-actions";

type Snapshot = { deviceId: string; capturedAt: string; steps: number; sleepMinutes: number; workouts: number };
type HealthConfig = { signingSecret?: string };
const snapshots = new Map<string, Snapshot>();
let lastDeviceId = "default";

function readBody(req: IncomingMessage): Promise<string> {
  return new Promise((resolve, reject) => {
    let body = "";
    req.setEncoding("utf8");
    req.on("data", (chunk) => { body += chunk; });
    req.on("end", () => resolve(body));
    req.on("error", reject);
  });
}

function requireDeviceId(value: unknown): string {
  const deviceId = typeof value === "string" ? value.trim() : "";
  if (!/^[A-Za-z0-9._:-]{1,80}$/.test(deviceId)) throw new Error("Invalid deviceId.");
  return deviceId;
}

function parseDate(value: string | undefined, label: string): number | undefined {
  if (!value) return undefined;
  const ms = Date.parse(value);
  if (!Number.isFinite(ms)) throw new Error(`${label} must be an ISO date or timestamp.`);
  return ms;
}

function verifySignature(secret: string, body: string, signature: unknown): boolean {
  if (typeof signature !== "string" || !signature.trim()) return false;
  const expected = createHmac("sha256", secret).update(body).digest("hex");
  const left = Buffer.from(signature.replace(/^sha256=/, ""), "hex");
  const right = Buffer.from(expected, "hex");
  return left.length === right.length && timingSafeEqual(left, right);
}

function normalizeSnapshot(raw: Record<string, unknown>): Snapshot {
  const capturedAt = typeof raw.capturedAt === "string" ? raw.capturedAt : new Date().toISOString();
  parseDate(capturedAt, "capturedAt");
  return {
    deviceId: requireDeviceId(raw.deviceId),
    capturedAt,
    steps: Math.max(0, Math.trunc(Number(raw.steps || 0))),
    sleepMinutes: Math.max(0, Math.trunc(Number(raw.sleepMinutes || 0))),
    workouts: Math.max(0, Math.trunc(Number(raw.workouts || 0))),
  };
}

function healthSummaryTool(): AnyAgentTool {
  return {
    name: "health_summary",
    label: "Health Summary",
    description: "Read the latest posted Apple Health summary for a device.",
    parameters: Type.Object({ deviceId: Type.Optional(Type.String()), startDate: Type.Optional(Type.String()), endDate: Type.Optional(Type.String()) }),
    execute: async (_id, raw) => {
      const deviceId = raw.deviceId === undefined ? lastDeviceId : requireDeviceId(raw.deviceId);
      const snapshot = snapshots.get(deviceId);
      if (!snapshot) return jsonResult({ status: "missing", deviceId });
      const captured = Date.parse(snapshot.capturedAt);
      const start = parseDate(readStringParam(raw, "startDate"), "startDate");
      const end = parseDate(readStringParam(raw, "endDate"), "endDate");
      if ((start !== undefined && captured < start) || (end !== undefined && captured > end)) {
        return jsonResult({ status: "outside_range", deviceId, capturedAt: snapshot.capturedAt });
      }
      return jsonResult({ status: "ok", ...snapshot });
    },
  };
}

export default definePluginEntry({
  id: "healthkit-bridge",
  name: "HealthKit Bridge",
  description: "Read-only Apple Health snapshot bridge.",
  register(api: OpenClawPluginApi) {
    api.registerHttpRoute({ path: "/plugins/healthkit/snapshot", auth: "plugin", handler: async (req, res) => {
      const body = await readBody(req);
      const secret = ((api.pluginConfig || {}) as HealthConfig).signingSecret;
      if (!secret || !verifySignature(secret, body, req.headers["x-openclaw-health-signature"])) { res.statusCode = 401; res.end("invalid signature"); return true; }
      const snapshot = normalizeSnapshot(JSON.parse(body) as Record<string, unknown>);
      snapshots.set(snapshot.deviceId, snapshot); lastDeviceId = snapshot.deviceId;
      res.setHeader("content-type", "application/json"); res.end(JSON.stringify({ ok: true, deviceId: snapshot.deviceId })); return true;
    } });
    api.registerTool(healthSummaryTool(), { name: "health_summary" });
  },
});
```

