import { normalizeLowercaseStringOrEmpty } from 'openclaw/plugin-sdk/text-runtime';

const ASSISTANT_PROCESS_CHATTER_RE = /^(?:assistant:\s*)?(?:need|now|oops)\b/i;
const TERSE_PROCESS_ACTION_RE = /^(?:assistant:\s*)?(?:inspect|commit|push|merge|poll|rebase|checkout|status)[.!]?$/i;
const DURABLE_SIGNAL_RE = /\b(?:confirmed|decided|approved|rejected|corrected|accepted|verified|pass|failed|merged)\b/i;
const DURABLE_ARTIFACT_RE = /\b(?:pr\s*#\d+|commit\s+[a-f0-9]{7,40}|[a-f0-9]{40})\b/i;

function normalizeSnippetForHygiene(raw: string): string {
  return normalizeLowercaseStringOrEmpty(raw.normalize('NFKC').replace(/\s+/g, ' ').trim());
}

export function shouldRejectDreamingSessionCorpusSnippet(raw: string): boolean {
  const snippet = normalizeSnippetForHygiene(raw);
  if (snippet.length === 0) return false;
  if (DURABLE_SIGNAL_RE.test(snippet) || DURABLE_ARTIFACT_RE.test(snippet)) return false;
  return ASSISTANT_PROCESS_CHATTER_RE.test(snippet) || TERSE_PROCESS_ACTION_RE.test(snippet);
}

// --- Integration point: collectSessionIngestionBatches' per-line ingestion loop in
// dreaming-phases.ts (~824-859). These module-private helpers/consts already exist there;
// shown inline so the loop body below typechecks as a faithful drop-in.
const SESSION_INGESTION_MAX_SNIPPET_CHARS = 280;
const SESSION_INGESTION_MIN_SNIPPET_CHARS = 12;

type SessionIngestionMessage = {
  day: string;
  snippet: string;
  rendered: string;
};

function normalizeSessionCorpusSnippet(value: string): string {
  return value.replace(/\s+/g, " ").trim().slice(0, SESSION_INGESTION_MAX_SNIPPET_CHARS);
}

function buildSessionRenderedLine(params: {
  agentId: string;
  sessionPath: string;
  lineNumber: number;
  snippet: string;
}): string {
  const source = `${params.agentId}/${params.sessionPath}#L${params.lineNumber}`;
  return `[${source}] ${params.snippet}`.slice(0, SESSION_INGESTION_MAX_SNIPPET_CHARS + 64);
}

declare const lines: string[];
declare const entry: { lineMap: number[] };
declare const file: { agentId: string; sessionPath: string };
declare const day: string;
declare const batchByDay: Map<string, SessionIngestionMessage[]>;

for (let index = 0; index < lines.length; index += 1) {
  const rawSnippet = lines[index] ?? "";
  const snippet = normalizeSessionCorpusSnippet(rawSnippet);
  if (snippet.length < SESSION_INGESTION_MIN_SNIPPET_CHARS) {
    continue;
  }
  // NEW: drop assistant process scratch before this snippet is rendered/appended.
  if (shouldRejectDreamingSessionCorpusSnippet(snippet)) {
    continue;
  }
  const lineNumber = entry.lineMap[index] ?? index + 1;
  const rendered = buildSessionRenderedLine({
    agentId: file.agentId,
    sessionPath: file.sessionPath,
    lineNumber,
    snippet,
  });
  const bucket = batchByDay.get(day) ?? [];
  bucket.push({ day, snippet, rendered });
  batchByDay.set(day, bucket);
}
