import type {
  MemorySearchManager,
  MemorySearchResult,
  MemorySearchRuntimeDebug,
} from 'openclaw/plugin-sdk/memory-core-host-runtime-files';
import type { OpenClawConfig } from 'openclaw/plugin-sdk/memory-core-host-runtime-core';
import {
  resolveMemoryCorePluginConfig,
  resolveMemoryDeepDreamingConfig,
} from 'openclaw/plugin-sdk/memory-core-host-status';
import { recordShortTermRecalls } from './short-term-promotion.js';
import { clampResultsByInjectedChars, decorateCitations } from './tools.citations.js';
import { loadMemoryToolRuntime } from './tools.shared.js';

// The promotion store keys recalls by the snapshot's stable result identity:
// (source, path, startLine, endLine) — NOT by snippet text or a tool-call id.
function buildRecallKey(
  result: Pick<MemorySearchResult, 'source' | 'path' | 'startLine' | 'endLine'>,
): string {
  return `${result.source}:${result.path}:${result.startLine}:${result.endLine}`;
}

// The tool path's extra step the command path never needs: map each result that
// was actually SURFACED to the model (post-decorate + post-qmd-clamp) back to its
// RAW counterpart, so the recorded snippet is the raw body — not the citation-
// decorated ("Source:" line baked in) / clamp-truncated text the model saw.
function resolveRecallTrackingResults(
  rawResults: MemorySearchResult[],
  surfacedResults: MemorySearchResult[],
): MemorySearchResult[] {
  if (surfacedResults.length === 0 || rawResults.length === 0) {
    return surfacedResults;
  }
  const rawByKey = new Map<string, MemorySearchResult>();
  for (const raw of rawResults) {
    const key = buildRecallKey(raw);
    if (!rawByKey.has(key)) {
      rawByKey.set(key, raw);
    }
  }
  return surfacedResults.map((surfaced) => rawByKey.get(buildRecallKey(surfaced)) ?? surfaced);
}

function queueShortTermRecallTracking(params: {
  workspaceDir?: string;
  query: string;
  rawResults: MemorySearchResult[];
  surfacedResults: MemorySearchResult[];
  timezone?: string;
}): void {
  const trackingResults = resolveRecallTrackingResults(params.rawResults, params.surfacedResults);
  // Best-effort: fire without awaiting and swallow errors so a slow/failed
  // recall write can never stall or fail the memory_search tool.
  void recordShortTermRecalls({
    workspaceDir: params.workspaceDir,
    query: params.query,
    results: trackingResults,
    timezone: params.timezone,
  }).catch(() => {
    // Recall tracking is best-effort and must never block memory recall.
  });
}

// Inside the memory_search tool's execute closure, after semantic search:
async function wireToolRecallTracking(args: {
  cfg: OpenClawConfig;
  agentId: string;
  query: string;
  maxResults?: number;
  minScore?: number;
  includeCitations: boolean;
  memory: { manager: MemorySearchManager };
  options: { agentSessionKey?: string };
}): Promise<MemorySearchResult[]> {
  const { cfg, agentId, query, maxResults, minScore, includeCitations, memory, options } = args;
  const { resolveMemoryBackendConfig } = await loadMemoryToolRuntime();
  const runtimeDebug: MemorySearchRuntimeDebug[] = [];

  const rawResults = await memory.manager.search(query, {
    maxResults,
    minScore,
    sessionKey: options.agentSessionKey,
    onDebug: (debug) => {
      runtimeDebug.push(debug);
    },
  });
  const status = memory.manager.status();
  const decorated = decorateCitations(rawResults, includeCitations);
  const resolved = resolveMemoryBackendConfig({ cfg, agentId });
  const memoryResults =
    status.backend === 'qmd'
      ? clampResultsByInjectedChars(decorated, resolved.qmd?.limits.maxInjectedChars)
      : decorated;

  // Day buckets must line up with the Dreaming engine, so the timezone comes from
  // the memory-core Dreaming config — NOT agents.defaults.userTimezone.
  const timezone = resolveMemoryDeepDreamingConfig({
    pluginConfig: resolveMemoryCorePluginConfig(cfg),
    cfg,
  }).timezone;

  queueShortTermRecallTracking({
    workspaceDir: status.workspaceDir,
    query,
    rawResults,
    surfacedResults: memoryResults,
    timezone,
  });

  return memoryResults;
}
