```ts
import { normalizeLowercaseStringOrEmpty } from 'openclaw/plugin-sdk/text-runtime';

// Mirrors the file-local snippet normalizer (trim + collapse whitespace) so the
// comparable-form helper composes on top of the same canonical text.
function normalizeSnippet(raw: string): string {
  const trimmed = raw.trim();
  if (!trimmed) {
    return '';
  }
  return trimmed.replace(/\s+/g, ' ');
}

function normalizeComparablePromotionText(value: string): string {
  const compact = normalizeLowercaseStringOrEmpty(
    normalizeSnippet(value)
      .replace(/`/g, '')
      .replace(/[.;,，。；：:]+/g, ' ')
      .replace(/\s+/g, ' ')
      .trim(),
  );
  return compact.replace(/^[^:：]{1,48}[:：]\s+/, '').trim();
}

function tokenOverlapScore(left: string, right: string): number {
  const leftTokens = new Set(left.split(/\s+/).filter((token) => token.length >= 3));
  const rightTokens = new Set(right.split(/\s+/).filter((token) => token.length >= 3));
  if (leftTokens.size === 0 || rightTokens.size === 0) return 0;
  let shared = 0;
  for (const token of leftTokens) if (rightTokens.has(token)) shared += 1;
  return shared / Math.min(leftTokens.size, rightTokens.size);
}

function compareCandidateWindow(targetSnippet: string, windowSnippet: string): { matched: boolean; quality: number } {
  if (!targetSnippet || !windowSnippet) return { matched: false, quality: 0 };
  if (windowSnippet === targetSnippet) return { matched: true, quality: 3 };
  if (windowSnippet.includes(targetSnippet)) return { matched: true, quality: 2 };
  if (targetSnippet.includes(windowSnippet)) return { matched: true, quality: 1 };

  const targetComparable = normalizeComparablePromotionText(targetSnippet);
  const windowComparable = normalizeComparablePromotionText(windowSnippet);
  if (!targetComparable || !windowComparable) return { matched: false, quality: 0 };
  if (windowComparable.includes(targetComparable) || targetComparable.includes(windowComparable)) return { matched: true, quality: 0.75 };
  return tokenOverlapScore(targetComparable, windowComparable) >= 0.82 ? { matched: true, quality: 0.5 } : { matched: false, quality: 0 };
}
