Keep the storage decision centralized in the phase markdown writer and preserve memory host events for both inline and separate modes.

```typescript
import fs from 'node:fs/promises';
import path from 'node:path';
import { formatMemoryDreamingDay, type MemoryDreamingPhaseName, type MemoryDreamingStorageConfig } from 'openclaw/plugin-sdk/memory-core-host-status';
import { appendMemoryHostEvent } from 'openclaw/plugin-sdk/memory-host-events';
import { replaceManagedMarkdownBlock, withTrailingNewline } from 'openclaw/plugin-sdk/memory-host-markdown';

function shouldWriteInline(storage: MemoryDreamingStorageConfig): boolean {
  return storage.mode === 'inline' || storage.mode === 'both';
}

function shouldWriteSeparate(storage: MemoryDreamingStorageConfig): boolean {
  return storage.mode === 'separate' || storage.mode === 'both' || storage.separateReports;
}

export async function writeDailyDreamingPhaseBlock(params: { workspaceDir: string; phase: Exclude<MemoryDreamingPhaseName, 'deep'>; bodyLines: string[]; nowMs?: number; timezone?: string; storage: MemoryDreamingStorageConfig }): Promise<{ inlinePath?: string; reportPath?: string }> {
  const nowMs = Number.isFinite(params.nowMs) ? (params.nowMs as number) : Date.now();
  const day = formatMemoryDreamingDay(nowMs, params.timezone);
  const body = params.bodyLines.length > 0 ? params.bodyLines.join('\n') : '- No notable updates.';
  let inlinePath: string | undefined;
  let reportPath: string | undefined;

  if (shouldWriteInline(params.storage)) {
    inlinePath = path.join(params.workspaceDir, 'memory', `${day}.md`);
    await fs.mkdir(path.dirname(inlinePath), { recursive: true });
    const original = await fs.readFile(inlinePath, 'utf-8').catch((err: NodeJS.ErrnoException) => err.code === 'ENOENT' ? '' : Promise.reject(err));
    const updated = replaceManagedMarkdownBlock({ original, heading: params.phase === 'light' ? '## Light Sleep' : '## REM Sleep', startMarker: `<!-- openclaw:dreaming:${params.phase}:start -->`, endMarker: `<!-- openclaw:dreaming:${params.phase}:end -->`, body });
    await fs.writeFile(inlinePath, withTrailingNewline(updated), 'utf-8');
  }

  if (shouldWriteSeparate(params.storage)) {
    reportPath = path.join(params.workspaceDir, 'memory', 'dreaming', params.phase, `${day}.md`);
    await fs.mkdir(path.dirname(reportPath), { recursive: true });
    await fs.writeFile(reportPath, `# ${params.phase === 'light' ? 'Light Sleep' : 'REM Sleep'}\n\n${body}\n`, 'utf-8');
  }

  await appendMemoryHostEvent(params.workspaceDir, { type: 'memory.dream.completed', timestamp: new Date(nowMs).toISOString(), phase: params.phase, inlinePath, reportPath, lineCount: params.bodyLines.length, storageMode: params.storage.mode });
  return { inlinePath, reportPath };
}
